#!/usr/bin/env python3
"""Deterministically build the ``miniproject`` test fixture.

The fixture is a real git repository (a small task-tracker called *taskhub*
with a Python backend and a TypeScript frontend) used by the test suite and
the eval gold set. It is generated by this script rather than committed as a
tarball so it stays reviewable and reproducible (see DECISIONS.md).

Determinism: fixed author/committer identity and timestamps, fixed branch
name (``main``), fixed file contents. Building twice yields byte-identical
history (same commit SHAs).

Usage::

    python tests/fixtures/build_miniproject.py [dest]   # default: ./miniproject
"""

from __future__ import annotations

import os
import shutil
import subprocess
import sys
from pathlib import Path

