def _git(repo: Path, *args: str, day: int) -> None:
    date = _BASE_DATE.format(day=day)
    env = dict(
        os.environ,
        GIT_AUTHOR_NAME=_AUTHOR_NAME,
        GIT_AUTHOR_EMAIL=_AUTHOR_EMAIL,
        GIT_COMMITTER_NAME=_AUTHOR_NAME,
        GIT_COMMITTER_EMAIL=_AUTHOR_EMAIL,
        GIT_AUTHOR_DATE=date,
        GIT_COMMITTER_DATE=date,
        HOME=str(repo),  # ignore user-level git config for determinism
        GIT_CONFIG_NOSYSTEM="1",
    )
    subprocess.run(["git", *args], cwd=repo, env=env, check=True, capture_output=True)


def build(dest: Path) -> Path:
    """Build the fixture repo at ``dest`` (removed first if it exists)."""
    dest = dest.resolve()
    if dest.exists():
        shutil.rmtree(dest)
    dest.mkdir(parents=True)

    _git(dest, "init", "--quiet", "--initial-branch=main", day=1)
    _git(dest, "config", "commit.gpgsign", "false", day=1)

    for day, (message, files) in enumerate(COMMITS, start=1):
        for rel_path, content in files.items():
            target = dest / rel_path
            if content is None:
                _git(dest, "rm", "--quiet", rel_path, day=day)
                continue
            target.parent.mkdir(parents=True, exist_ok=True)
            target.write_text(content, encoding="utf-8", newline="\n")
            _git(dest, "add", rel_path, day=day)
        _git(dest, "commit", "--quiet", "-m", message, day=day)

    # marker lives inside .git so the fixture's working tree stays clean
    (dest / ".git" / _VERSION_MARKER).write_text(str(FIXTURE_VERSION), encoding="utf-8")
    return dest


def main() -> int:
    default_dest = Path(__file__).parent / FIXTURE_DIRNAME
    dest = Path(sys.argv[1]) if len(sys.argv) > 1 else default_dest
    built = build(dest)
    head = subprocess.run(
        ["git", "rev-parse", "HEAD"], cwd=built, check=True, capture_output=True, text=True
    ).stdout.strip()
    print(f"miniproject fixture built at {built} (HEAD {head[:12]})")
    return 0


if __name__ == "__main__":
    sys.exit(main())
